#include<bits/stdc++.h>
using namespace std;
int n,m,tot,ans,rt,sum,min1,cnt;
int val[200010],head[200010],siz[200010],fa[200010],d[200010],pos[200010],ol[400010][21],lg[400010];
bool vis[400010];
vector<int> c[2][400010];
struct edge
{
    int n,v;
}e[400010];
void add(int u,int v)
{
    e[++tot]=(edge){head[u],v};
    head[u]=tot;
}
void dfs0(int x,int fa)
{
    ol[++cnt][0]=x;
    pos[x]=cnt;
    for(int i=head[x];i;i=e[i].n)
    {
        int v=e[i].v;
        if(v!=fa)
        {
            d[v]=d[x]+1;
            dfs0(v,x);
            ol[++cnt][0]=x;
        }
    }
}
int getmin(int x,int y)
{
    return(d[x]<d[y]?x:y);
}
void getol()
{
    for(int i=1;i<=cnt;i++)
    {
        lg[i]=__lg(i);
    }
    for(int t=1;(1<<t)<=cnt;t++)
    {
        for(int i=1;i+(1<<t)<=cnt;i++)
        {
            ol[i][t]=getmin(ol[i][t-1],ol[i+(1<<(t-1))][t-1]);
        }
    }
}
int getdis(int x,int y)
{
    if(pos[x]>pos[y])
    {
        swap(x,y);
    }
    int u=pos[x],v=pos[y];
    int len=v-u+1;
    int lca=getmin(ol[u][lg[len]],ol[v-(1<<lg[len])+1][lg[len]]);
    return d[x]+d[y]-d[lca]*2;
}
int lowbit(int x)
{
    return x&-x;
}
void update(int u,int op,int x,int val)
{
    x++;
    for(int i=x;i<=siz[u];i+=lowbit(i))
    {
        c[op][u][i]+=val;
    }
}
int query(int u,int op,int x)
{
    x++;
    int ans=0;
    x=min(x,siz[u]);
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=c[op][u][i];
    }
    return ans;
}
void findrt(int x,int fa)
{
    siz[x]=1;
    int ans=0;
    for(int i=head[x];i;i=e[i].n)
    {
        int v=e[i].v;
        if(v!=fa&&!vis[v])
        {
            findrt(v,x);
            siz[x]+=siz[v];
            ans=max(ans,siz[v]);
        }
    }
    ans=max(ans,sum-siz[x]);
    if(ans<min1)
    {
        min1=ans;
        rt=x;
    }
}
void dfs(int x)
{
    vis[x]=1;
    siz[x]=sum+1;
    c[0][x].resize(siz[x]+1);
    c[1][x].resize(siz[x]+1);
    for(int i=head[x];i;i=e[i].n)
    {
        int v=e[i].v;
        if(!vis[v])
        {
            sum=siz[v];
            rt=0;
            min1=1e9;
            findrt(v,0);
            fa[rt]=x;
            dfs(rt);
        }
    }
}
void change(int x,int w)
{
    for(int i=x;i;i=fa[i])
    {
        update(i,0,getdis(x,i),w);
    }
    for(int i=x;fa[i];i=fa[i])
    {
        update(i,1,getdis(x,fa[i]),w);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
        add(v,u);
    }
    dfs0(1,0);
    getol();
    sum=n;
    min1=1e9;
    findrt(1,0);
    dfs(rt);
    for(int i=1;i<=n;i++)
    {
        change(i,val[i]);
    }
    int lstans=0;
    while(m--)
    {
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        x^=lstans;
        y^=lstans;
        if(op==0)
        {
            ans=0;
            ans+=query(x,0,y);
            for(int i=x;fa[i];i=fa[i])
            {
                int dis=getdis(x,fa[i]);
                if(y>=dis)
                {
                    ans+=query(fa[i],0,y-dis)-query(i,1,y-dis);
                }
            }
            printf("%d\n",lstans=ans);
        }
        else
        {
            change(x,y-val[x]);
            val[x]=y;
        }
    }
    return 0;
}
